using System;
using System.Collections.Generic;
using GTA;
using GTA.Math;
using GTA.Native;
using ModProject.LiveStudio;

namespace ModProject
{
    public class Mod : Script
    {
        private LiveStudioClient _client;

        // Challenge state
        private bool _challengeActive;
        private DateTime _challengeStartTime;
        private static readonly TimeSpan ChallengeDuration = TimeSpan.FromMinutes(15);

        // Locations
        private static readonly Vector3 StartPosition = new Vector3(2875.5f, 5216.8f, 26.5f);
        private static readonly Vector3 SummitPosition = new Vector3(2849.7f, 5000.7f, 127.7f);
        private const float TriggerDistance = 5.0f;

        // Effect cooldowns (key = effect id, value = next available time)
        private readonly Dictionary<string, DateTime> _cooldowns = new Dictionary<string, DateTime>();

        // Timed effect expirations
        private DateTime _speedBoostExpiry = DateTime.MinValue;
        private DateTime _drunkExpiry = DateTime.MinValue;
        private DateTime _weatherThunderTime = DateTime.MinValue;
        private DateTime _weatherRevertTime = DateTime.MinValue;
        private bool _weatherActive;

        // Spawned hostile peds
        private readonly List<Ped> _hostilePeds = new List<Ped>();

        // Random for spawn positions
        private readonly Random _random = new Random();

        public Mod()
        {
            Tick += OnTick;
            Aborted += OnAborted;

            _client = new LiveStudioClient(
                onEvent: HandleEvent,
                onLog: msg => MainThreadDispatcher.Enqueue(() => GTA.UI.Notification.Show("~y~" + msg))
            );
            _client.Start();

            GTA.UI.Notification.Show("~g~Mount Chiliad Pilgrimage mod loaded.~n~~w~Go to the trailhead to begin.");
        }

        private void OnTick(object sender, EventArgs e)
        {
            MainThreadDispatcher.DrainOnTick();

            if (_challengeActive)
            {
                Player player = Game.Player;
                Ped character = player.Character;

                // Death check
                if (character.IsDead)
                {
                    EndChallenge(false, "You died! Pilgrimage failed.");
                    return;
                }

                // Arrest check
                if (Function.Call<bool>(Hash.IS_PLAYER_BEING_ARRESTED, player.Handle, 0))
                {
                    EndChallenge(false, "You were arrested! Pilgrimage failed.");
                    return;
                }

                // Time-out check
                TimeSpan remaining = (_challengeStartTime + ChallengeDuration) - DateTime.Now;
                if (remaining <= TimeSpan.Zero)
                {
                    EndChallenge(false, "Time's up! Pilgrimage failed.");
                    return;
                }

                // Summit arrival (must have time remaining > 0)
                if (remaining.TotalSeconds > 0 && character.Position.DistanceTo(SummitPosition) < TriggerDistance)
                {
                    EndChallenge(true, "~g~You reached the summit! Pilgrimage complete!");
                    return;
                }

                // Display remaining time and distance
                GTA.UI.Screen.ShowSubtitle(
                    "~w~Time: ~y~" + string.Format("{0:D2}:{1:D2}", remaining.Minutes, remaining.Seconds) +
                    "  ~w~Distance: ~y~" + Math.Round(character.Position.DistanceTo(SummitPosition), 1) + "m"
                );

                // Handle timed effect expirations
                DateTime now = DateTime.Now;

                if (_speedBoostExpiry != DateTime.MinValue && now >= _speedBoostExpiry)
                {
                    Function.Call(Hash.SET_PED_MOVE_RATE_OVERRIDE, character.Handle, 1.0f);
                    _speedBoostExpiry = DateTime.MinValue;
                }

                if (_drunkExpiry != DateTime.MinValue && now >= _drunkExpiry)
                {
                    Function.Call(Hash.SET_PED_DRUNK, character.Handle, false, 0);
                    _drunkExpiry = DateTime.MinValue;
                }

                if (_weatherActive)
                {
                    if (_weatherThunderTime != DateTime.MinValue && now >= _weatherThunderTime)
                    {
                        World.Weather = Weather.ThunderStorm;
                        _weatherThunderTime = DateTime.MinValue;
                    }
                    if (_weatherRevertTime != DateTime.MinValue && now >= _weatherRevertTime)
                    {
                        World.Weather = Weather.Clear;
                        _weatherActive = false;
                        _weatherRevertTime = DateTime.MinValue;
                    }
                }
            }
            else
            {
                // Check if player enters start zone
                if (Game.Player.Character.Position.DistanceTo(StartPosition) < TriggerDistance)
                {
                    StartChallenge();
                }
            }
        }

        private void StartChallenge()
        {
            _challengeActive = true;
            _challengeStartTime = DateTime.Now;

            // Reset all effect state
            _speedBoostExpiry = DateTime.MinValue;
            _drunkExpiry = DateTime.MinValue;
            _weatherThunderTime = DateTime.MinValue;
            _weatherRevertTime = DateTime.MinValue;
            _weatherActive = false;
            _cooldowns.Clear();

            // Clean up spawned hostile peds from previous run
            CleanupHostilePeds();

            // Reset player state
            Player player = Game.Player;
            Ped character = player.Character;
            Function.Call(Hash.SET_PED_MOVE_RATE_OVERRIDE, character.Handle, 1.0f);
            Function.Call(Hash.SET_PED_DRUNK, character.Handle, false, 0);
            World.Weather = Weather.Clear;

            GTA.UI.Notification.Show("~g~Pilgrimage begins!~n~~w~Reach the summit within 15 minutes. Good luck!");
        }

        private void EndChallenge(bool success, string message)
        {
            _challengeActive = false;
            GTA.UI.Notification.Show(message);

            // Reset persistent effects
            Ped character = Game.Player.Character;
            Function.Call(Hash.SET_PED_MOVE_RATE_OVERRIDE, character.Handle, 1.0f);
            _speedBoostExpiry = DateTime.MinValue;

            Function.Call(Hash.SET_PED_DRUNK, character.Handle, false, 0);
            _drunkExpiry = DateTime.MinValue;

            if (_weatherActive)
            {
                World.Weather = Weather.Clear;
                _weatherActive = false;
                _weatherThunderTime = DateTime.MinValue;
                _weatherRevertTime = DateTime.MinValue;
            }

            _cooldowns.Clear();
            CleanupHostilePeds();
        }

        private void CleanupHostilePeds()
        {
            for (int i = _hostilePeds.Count - 1; i >= 0; i--)
            {
                Ped ped = _hostilePeds[i];
                if (ped != null && ped.Exists())
                {
                    ped.Delete();
                }
                _hostilePeds.RemoveAt(i);
            }
        }

        private void OnAborted(object sender, EventArgs e)
        {
            if (_challengeActive)
            {
                // Reset persistent effects in case script is stopped mid-challenge
                Ped character = Game.Player.Character;
                Function.Call(Hash.SET_PED_MOVE_RATE_OVERRIDE, character.Handle, 1.0f);
                Function.Call(Hash.SET_PED_DRUNK, character.Handle, false, 0);
                if (_weatherActive)
                {
                    World.Weather = Weather.Clear;
                }
            }

            CleanupHostilePeds();
            _client?.Dispose();
        }

        private void HandleEvent(LiveStudioEvent evt)
        {
            if (evt is ChatEvent chat)
            {
                string content = chat.Content?.Trim().ToLowerInvariant();
                if (string.IsNullOrEmpty(content)) return;

                MainThreadDispatcher.Enqueue(() =>
                {
                    if (!_challengeActive) return;

                    if (content == "!heal")
                        ApplyEffectWithCooldown("heal", 30, RestoreHealth);
                    else if (content == "!armor")
                        ApplyEffectWithCooldown("armor", 30, ReplenishArmor);
                    else if (content == "!speed")
                        ApplyEffectWithCooldown("speed", 60, ApplySpeedBoost);
                    else if (content == "!clear")
                        ApplyEffectWithCooldown("clear", 45, ClearNearbyHostiles);
                    else if (content == "!parachute")
                        ApplyEffectWithCooldown("parachute", 120, GiveParachute);
                    else if (content == "!fog")
                        ApplyEffectWithCooldown("fog", 90, ApplyFogCurse);
                    else if (content == "!stumble")
                        ApplyEffectWithCooldown("stumble", 20, ApplyStumble);
                    else if (content == "!drunk")
                        ApplyEffectWithCooldown("drunk", 45, ApplyDrunk);
                    else if (content == "!enemy")
                        ApplyEffectWithCooldown("enemy", 25, SpawnHostileClimber);
                    else if (content == "!wanted")
                        ApplyEffectWithCooldown("wanted", 120, IncreaseWantedLevel);
                });
            }

            if (evt is GiftEvent gift)
            {
                if (!gift.RepeatEnd) return;

                string giftId = gift.GiftId;
                if (string.IsNullOrEmpty(giftId)) return;

                MainThreadDispatcher.Enqueue(() =>
                {
                    if (!_challengeActive) return;

                    if (giftId == "CHILIAD_BLESS_HEAL")
                        ApplyEffectWithCooldown("gift_heal", 30, RestoreHealth);
                    else if (giftId == "CHILIAD_BLESS_ARMOR")
                        ApplyEffectWithCooldown("gift_armor", 30, ReplenishArmor);
                    else if (giftId == "CHILIAD_BLESS_SPEED")
                        ApplyEffectWithCooldown("gift_speed", 60, ApplySpeedBoost);
                    else if (giftId == "CHILIAD_BLESS_CLEAR")
                        ApplyEffectWithCooldown("gift_clear", 45, ClearNearbyHostiles);
                    else if (giftId == "CHILIAD_BLESS_CHUTE")
                        ApplyEffectWithCooldown("gift_parachute", 120, GiveParachute);
                    else if (giftId == "CHILIAD_CURSE_FOG")
                        ApplyEffectWithCooldown("gift_fog", 90, ApplyFogCurse);
                    else if (giftId == "CHILIAD_CURSE_STUMBLE")
                        ApplyEffectWithCooldown("gift_stumble", 20, ApplyStumble);
                    else if (giftId == "CHILIAD_CURSE_DRUNK")
                        ApplyEffectWithCooldown("gift_drunk", 45, ApplyDrunk);
                    else if (giftId == "CHILIAD_CURSE_ENEMY")
                        ApplyEffectWithCooldown("gift_enemy", 25, SpawnHostileClimber);
                    else if (giftId == "CHILIAD_CURSE_WANTED")
                        ApplyEffectWithCooldown("gift_wanted", 120, IncreaseWantedLevel);
                });
            }
        }

        private void ApplyEffectWithCooldown(string effectKey, int cooldownSeconds, Action effectAction)
        {
            DateTime now = DateTime.Now;
            if (_cooldowns.TryGetValue(effectKey, out DateTime nextAvailable) && now < nextAvailable)
                return;

            _cooldowns[effectKey] = now.AddSeconds(cooldownSeconds);
            effectAction();
        }

        // --- Positive Effects ---

        private void RestoreHealth()
        {
            Ped character = Game.Player.Character;
            character.Health = character.MaxHealth;
            GTA.UI.Notification.Show("~g~Health restored!");
        }

        private void ReplenishArmor()
        {
            Ped character = Game.Player.Character;
            character.Armor = 100;
            GTA.UI.Notification.Show("~g~Armor replenished!");
        }

        private void ApplySpeedBoost()
        {
            Ped character = Game.Player.Character;
            Function.Call(Hash.SET_PED_MOVE_RATE_OVERRIDE, character.Handle, 1.5f);
            _speedBoostExpiry = DateTime.Now.AddSeconds(8);
            GTA.UI.Notification.Show("~g~Speed boost for 8 seconds!");
        }

        private void ClearNearbyHostiles()
        {
            Ped playerPed = Game.Player.Character;
            Vector3 playerPos = playerPed.Position;
            Ped[] nearbyPeds = World.GetNearbyPeds(playerPos, 50f);

            int cleared = 0;
            foreach (Ped ped in nearbyPeds)
            {
                if (ped == null || !ped.Exists()) continue;
                if (ped == playerPed) continue;
                if (ped.IsMissionEnt) continue;

                if (Function.Call<bool>(Hash.IS_PED_IN_COMBAT, ped.Handle, playerPed.Handle))
                {
                    ped.Delete();
                    cleared++;
                }
            }

            GTA.UI.Notification.Show("~g~Cleared " + cleared + " hostile NPCs nearby.");
        }

        private void GiveParachute()
        {
            Ped character = Game.Player.Character;
            if (!character.Weapons.HasWeapon(WeaponHash.Parachute))
            {
                character.Weapons.Give(WeaponHash.Parachute, 1, false, true);
                GTA.UI.Notification.Show("~g~Parachute added!");
            }
            else
            {
                GTA.UI.Notification.Show("~y~You already have a parachute.");
            }
        }

        // --- Negative Effects ---

        private void ApplyFogCurse()
        {
            World.Weather = Weather.Foggy;
            _weatherActive = true;
            _weatherThunderTime = DateTime.Now.AddSeconds(3);
            _weatherRevertTime = DateTime.Now.AddSeconds(120);
            GTA.UI.Notification.Show("~r~Weather curse: Fog rolling in...");
        }

        private void ApplyStumble()
        {
            Ped character = Game.Player.Character;

            // Force player out of vehicle if inside one
            if (character.IsInVehicle())
            {
                Vehicle vehicle = character.CurrentVehicle;
                if (vehicle != null && vehicle.Exists())
                {
                    character.Task.LeaveVehicle(vehicle, LeaveVehicleFlags.LeaveDoorOpen);
                }
            }

            // Immediately apply ragdoll
            Function.Call(Hash.SET_PED_TO_RAGDOLL, character.Handle, 2000, 2000, 0, false, false, false);
            GTA.UI.Notification.Show("~r~Stumble!");
        }

        private void ApplyDrunk()
        {
            Ped character = Game.Player.Character;
            Function.Call(Hash.SET_PED_DRUNK, character.Handle, true, 0);
            _drunkExpiry = DateTime.Now.AddSeconds(15);
            GTA.UI.Notification.Show("~r~Feeling dizzy... (15s)");
        }

        private void SpawnHostileClimber()
        {
            Player player = Game.Player;
            Ped playerPed = player.Character;
            Vector3 playerPos = playerPed.Position;

            float angle = (float)(_random.NextDouble() * Math.PI * 2);
            float distance = (float)(_random.NextDouble() * 10 + 10); // 10–20 metres
            Vector3 offset = new Vector3(
                (float)Math.Cos(angle) * distance,
                (float)Math.Sin(angle) * distance,
                0f
            );
            Vector3 spawnPos = playerPos + offset;
            spawnPos.Z = World.GetGroundHeight(spawnPos);

            Ped hostilePed = World.CreatePed(PedHash.Hillbilly01, spawnPos, (float)(_random.NextDouble() * 360f));
            if (hostilePed == null || !hostilePed.Exists()) return;

            hostilePed.Weapons.Give(WeaponHash.Knife, 1, false, true);
            hostilePed.Task.FightAgainst(playerPed);

            _hostilePeds.Add(hostilePed);
            GTA.UI.Notification.Show("~r~A hostile climber appears!");
        }

        private void IncreaseWantedLevel()
        {
            Player player = Game.Player;
            int newWanted = Math.Min(player.WantedLevel + 1, 5);
            player.WantedLevel = newWanted;
            GTA.UI.Notification.Show("~r~Wanted level increased to " + newWanted + " star(s)!");
        }
    }
}
